interface ICheckable { string GetStatus(); }

class DryerBox : ICheckable
{ public string GetStatus() { return "烘干箱正常"; } }

class Motor : ICheckable
{ public string GetStatus() { return "电机正常"; } }

class Heater : ICheckable
{ public string GetStatus() { return "加热器正常"; } }

var devices = new List<ICheckable>();
devices.Add(new DryerBox());
devices.Add(new Motor());
devices.Add(new Heater());

foreach (var d in devices)
    Print(d.GetStatus());
